//! bench-jar-shootoff — VOLUME run that computes the whole Taylor (Keystone)
//! Sequence and routes it through the jar tiers.
//!
//! The workload is real: for every n < N, test Phyle-Tripod membership
//! (n is a Fibonacci-sum AND a Lucas-sum AND a Fibonacci×Lucas product). Each
//! test is a cache probe — binned to a lane per tier (E8/Leech/Kaiju) so we see
//! lane contention at volume. AND we collect + classify every Taylor number
//! (Lucas Lₖ / double 2Lₖ / transient) to learn whether the L∪2L structure holds
//! far past the ~20k we'd seen. Memory stays flat (counters + the sparse hit set).
//!
//! Usage: bench-jar-shootoff [N]   (default 2_000_000; crank it to really let rip)

use std::time::Instant;

use distributed_inference::hope_jar_e8::HopeJarE8;
use distributed_inference::hope_jar_kaiju::HopeJarKaiju;
use distributed_inference::hope_jar_leech::HopeJarLeech;

const GOLDEN: u64 = 0x9e37_79b9_7f4a_7c15;

fn fib_lucas(limit: u64) -> (Vec<u64>, Vec<u64>) {
    let mut f = vec![0u64, 1];
    while *f.last().unwrap() <= limit {
        let n = f[f.len() - 1] + f[f.len() - 2];
        f.push(n);
    }
    let mut l = vec![2u64, 1];
    while *l.last().unwrap() <= limit {
        let n = l[l.len() - 1] + l[l.len() - 2];
        l.push(n);
    }
    (f, l)
}

#[inline]
fn is_fib_sum(n: u64, f: &[u64]) -> bool {
    for a in 2..f.len() {
        if f[a] > n { break; }
        for b in a..f.len() {
            let s = f[a] + f[b];
            if s == n { return true; }
            if s > n { break; }
        }
    }
    false
}
#[inline]
fn is_lucas_sum(n: u64, l: &[u64]) -> bool {
    for a in 2..l.len() {
        if l[a] > n { break; }
        for b in a..l.len() {
            let s = l[a] + l[b];
            if s == n { return true; }
            if s > n { break; }
        }
    }
    false
}
#[inline]
fn is_fib_lucas_product(n: u64, f: &[u64], l: &[u64]) -> bool {
    for a in 1..f.len() {
        if f[a] > n { break; }
        for &lb in l.iter().skip(1) {
            let p = f[a] * lb;
            if p == n { return true; }
            if p > n { break; }
        }
    }
    false
}
#[inline]
fn is_tripod(n: u64, f: &[u64], l: &[u64]) -> bool {
    n > 0 && is_fib_sum(n, f) && is_lucas_sum(n, l) && is_fib_lucas_product(n, f, l)
}

fn lane_contention(name: &str, phases: u64, lanes: usize, predict: impl Fn(u64) -> u64, keys: u64) -> u64 {
    let mut load = vec![0u64; lanes];
    let mut acc = 0u64;
    let t = Instant::now();
    for h in 0..keys {
        let mixed = h.wrapping_mul(GOLDEN);
        acc ^= predict(mixed);
        let lane = ((mixed / phases) % lanes as u64) as usize;
        load[lane] += 1;
    }
    let secs = t.elapsed().as_secs_f64().max(1e-9);
    let max_load = *load.iter().max().unwrap_or(&0);
    let used = load.iter().filter(|&&c| c > 0).count();
    println!(
        "  {:<7} lanes {:>7} | {:>8.1} M key/s | lanes used {:>7} | max lane load {:>10} | sink {}",
        name, lanes, (keys as f64 / secs) / 1e6, used, max_load, acc & 0xff,
    );
    max_load
}

fn main() {
    let n: u64 = std::env::args().nth(1).and_then(|a| a.parse().ok()).unwrap_or(2_000_000);
    let (f, l) = fib_lucas(n + 2);
    let lset: std::collections::HashSet<u64> = l.iter().copied().collect();
    let l2set: std::collections::HashSet<u64> = l.iter().map(|&x| 2 * x).collect();

    println!("=== computing the Taylor (Keystone) Sequence for n < {} ===", n);
    let t = Instant::now();
    let mut taylor = Vec::new();
    for k in 1..n {
        if is_tripod(k, &f, &l) {
            taylor.push(k);
        }
    }
    let secs = t.elapsed().as_secs_f64();

    // classify every term: Lucas / double-Lucas / transient (NOT on the rail)
    let transient: Vec<u64> = taylor.iter().copied()
        .filter(|x| !lset.contains(x) && !l2set.contains(x)).collect();
    let on_lucas = taylor.iter().filter(|x| lset.contains(x)).count();
    let on_double = taylor.iter().filter(|x| l2set.contains(x)).count();

    println!("found {} Taylor numbers in {:.2}s ({:.1} M tested/s)", taylor.len(), secs, (n as f64/secs)/1e6);
    println!("  on Lucas rail Lₖ:        {}", on_lucas);
    println!("  on double rail 2Lₖ:      {}", on_double);
    println!("  TRANSIENT (neither):     {}  -> {:?}", transient.len(), transient);
    println!("  last 12 terms: {:?}", &taylor[taylor.len().saturating_sub(12)..]);
    println!("  largest term: {}", taylor.last().copied().unwrap_or(0));

    let keys: u64 = std::env::args().nth(2).and_then(|a| a.parse().ok()).unwrap_or(200_000_000);
    println!("\n=== routing {} dense cache keys through each jar tier (lane contention) ===", keys);
    let s = (0..170u64).map(|i| i.wrapping_mul(2654435761).wrapping_add(1)).collect::<Vec<_>>();
    let mut e8 = HopeJarE8::new(); e8.charge_from_seeds(&s, 1000);
    let e8m = lane_contention("E8", 30, 240, |h| e8.predict(h), keys);
    let mut le = HopeJarLeech::new(); le.charge_from_seeds(&s, 1000);
    let _ = lane_contention("Leech", 30, 720, |h| le.predict(h), keys);
    let mut ka = HopeJarKaiju::new(); ka.charge_from_seeds(&s, 1000);
    let kam = lane_contention("Kaiju", 24, 196_560, |h| ka.predict(h), keys);
    println!(
        "\nparallel bottleneck: E8's slowest lane {} keys vs Kaiju's {} — {:.0}× less serialized (run sideways)",
        e8m, kam, e8m as f64 / kam.max(1) as f64,
    );
}
